import {{ Injectable }} from '@nestjs/common';
import {{ FileService }} from './models/file.model';
import {{ FileServiceRepository }} from './repositories/file.repository';

@Injectable()
export class FileServiceService {{
  constructor(
    private readonly repository: FileServiceRepository,
  ) {{}}

  async findAll(): Promise<FileService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<FileService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<FileService>): Promise<FileService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<FileService>): Promise<FileService> {{
    return this.repository.update(id, data);
  }}
}}
